public class PrimsFibonacciHeap {

    public static int primsFibonacciHeap(int[] arr) {
        int n = arr[0], m = arr[1];
        List<List<int[]>> adj = new ArrayList<>();
        for (int i = 0; i < n; i++) adj.add(new ArrayList<>());
        for (int i = 0; i < m; i++) {
            int u = arr[2 + 3 * i], v = arr[2 + 3 * i + 1], w = arr[2 + 3 * i + 2];
            adj.get(u).add(new int[]{w, v});
            adj.get(v).add(new int[]{w, u});
        }

        boolean[] inMst = new boolean[n];
        int[] key = new int[n];
        Arrays.fill(key, Integer.MAX_VALUE);
        key[0] = 0;
        PriorityQueue<int[]> pq = new PriorityQueue<>((a, b) -> a[0] - b[0]);
        pq.add(new int[]{0, 0});
        int total = 0;

        while (!pq.isEmpty()) {
            int[] top = pq.poll();
            int w = top[0], u = top[1];
            if (inMst[u]) continue;
            inMst[u] = true;
            total += w;
            for (int[] edge : adj.get(u)) {
                int ew = edge[0], v = edge[1];
                if (!inMst[v] && ew < key[v]) {
                    key[v] = ew;
                    pq.add(new int[]{ew, v});
                }
            }
        }

        return total;
    }
}

import java.util.PriorityQueue

fun primsFibonacciHeap(arr: IntArray): Int {
    val n = arr[0]; val m = arr[1]
    val adj = Array(n) { mutableListOf<Pair<Int, Int>>() }
    for (i in 0 until m) {
        val u = arr[2+3*i]; val v = arr[2+3*i+1]; val w = arr[2+3*i+2]
        adj[u].add(Pair(w, v)); adj[v].add(Pair(w, u))
    }

    val inMst = BooleanArray(n)
    val key = IntArray(n) { Int.MAX_VALUE }
    key[0] = 0
    val pq = PriorityQueue<Pair<Int, Int>>(compareBy { it.first })
    pq.add(Pair(0, 0))
    var total = 0

    while (pq.isNotEmpty()) {
        val (w, u) = pq.poll()
        if (inMst[u]) continue
        inMst[u] = true; total += w
        for ((ew, v) in adj[u]) {
            if (!inMst[v] && ew < key[v]) { key[v] = ew; pq.add(Pair(ew, v)) }
        }
    }

    return total
}

use std::collections::BinaryHeap;
use std::cmp::Reverse;

pub fn prims_fibonacci_heap(arr: &[i32]) -> i32 {
    let n = arr[0] as usize;
    let m = arr[1] as usize;
    let mut adj: Vec<Vec<(i32, usize)>> = vec![vec![]; n];
    for i in 0..m {
        let u = arr[2 + 3 * i] as usize;
        let v = arr[2 + 3 * i + 1] as usize;
        let w = arr[2 + 3 * i + 2];
        adj[u].push((w, v));
        adj[v].push((w, u));
    }

    let inf = i32::MAX;
    let mut in_mst = vec![false; n];
    let mut key = vec![inf; n];
    key[0] = 0;
    let mut heap = BinaryHeap::new();
    heap.push(Reverse((0i32, 0usize)));
    let mut total = 0i32;

    while let Some(Reverse((w, u))) = heap.pop() {
        if in_mst[u] { continue; }
        in_mst[u] = true;
        total += w;
        for &(ew, v) in &adj[u] {
            if !in_mst[v] && ew < key[v] {
                key[v] = ew;
                heap.push(Reverse((ew, v)));
            }
        }
    }

    total
}

object PrimsFibonacciHeap {

  def primsFibonacciHeap(arr: Array[Int]): Int = {
    val n = arr(0); val m = arr(1)
    val adj = Array.fill(n)(scala.collection.mutable.ListBuffer[(Int, Int)]())
    for (i <- 0 until m) {
      val u = arr(2+3*i); val v = arr(2+3*i+1); val w = arr(2+3*i+2)
      adj(u) += ((w, v)); adj(v) += ((w, u))
    }

    val INF = Int.MaxValue
    val inMst = Array.fill(n)(false)
    val key = Array.fill(n)(INF)
    key(0) = 0
    val pq = scala.collection.mutable.PriorityQueue[(Int, Int)]()(Ordering.by[(Int, Int), Int](_._1).reverse)
    pq.enqueue((0, 0))
    var total = 0

    while (pq.nonEmpty) {
      val (w, u) = pq.dequeue()
      if (!inMst(u)) {
        inMst(u) = true; total += w
        for ((ew, v) <- adj(u)) {
          if (!inMst(v) && ew < key(v)) { key(v) = ew; pq.enqueue((ew, v)) }
        }
      }
    }

    total
  }
}

func primsFibonacciHeap(_ arr: [Int]) -> Int {
    let n = arr[0]; let m = arr[1]
    var adj = [[(Int, Int)]](repeating: [], count: n)
    for i in 0..<m {
        let u = arr[2+3*i], v = arr[2+3*i+1], w = arr[2+3*i+2]
        adj[u].append((w, v)); adj[v].append((w, u))
    }

    let INF = Int.max
    var inMst = [Bool](repeating: false, count: n)
    var key = [Int](repeating: INF, count: n)
    key[0] = 0
    var total = 0

    for _ in 0..<n {
        var u = -1
        for v in 0..<n {
            if !inMst[v] && (u == -1 || key[v] < key[u]) { u = v }
        }
        inMst[u] = true; total += key[u]
        for (w, v) in adj[u] {
            if !inMst[v] && w < key[v] { key[v] = w }
        }
    }

    return total
}

export function primsFibonacciHeap(arr: number[]): number {
    const n = arr[0], m = arr[1];
    const adj: [number, number][][] = Array.from({ length: n }, () => []);
    for (let i = 0; i < m; i++) {
        const u = arr[2+3*i], v = arr[2+3*i+1], w = arr[2+3*i+2];
        adj[u].push([w, v]); adj[v].push([w, u]);
    }

    const INF = 1e9;
    const inMst = new Array(n).fill(false);
    const key = new Array(n).fill(INF);
    key[0] = 0;
    // Simple O(V^2) for TS
    let total = 0;

    for (let iter = 0; iter < n; iter++) {
        let u = -1;
        for (let v = 0; v < n; v++) {
            if (!inMst[v] && (u === -1 || key[v] < key[u])) u = v;
        }
        inMst[u] = true;
        total += key[u];
        for (const [w, v] of adj[u]) {
            if (!inMst[v] && w < key[v]) key[v] = w;
        }
    }

    return total;
}
